import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:task_manager_flutter/data/models/venda_model.dart';
import 'package:task_manager_flutter/data/models/negotiation_model.dart';
import 'package:task_manager_flutter/data/utils/api_links.dart';
import 'package:task_manager_flutter/data/models/network_response.dart';
import 'package:task_manager_flutter/data/services/network_caller.dart';
import 'package:task_manager_flutter/data/models/auth_utility.dart';
import 'package:task_manager_flutter/ui/screens/LoginPopup_screens.dart';
import 'dart:io';
import 'package:path_provider/path_provider.dart';
import 'package:open_filex/open_filex.dart';
import 'package:http/http.dart' as http;
import 'dart:typed_data';
import 'package:http/http.dart' as http;
import 'package:task_manager_flutter/data/models/network_response.dart';
import 'package:task_manager_flutter/data/services/network_caller.dart';
import 'package:task_manager_flutter/data/utils/api_links.dart';

class FileCaller {
  Future<List<Map<String, dynamic>>> fetchDiretorios() async {
    final response = await NetworkCaller().getRequest(ApiLinks.allDiretorios);
    if (response.isSuccess && response.body != null) {
      final data = response.body!['data']['dados'] ?? [];
      return List<Map<String, dynamic>>.from(data);
    }
    return [];
  }

  Future<List<Map<String, dynamic>>> fetchArquivosPorDiretorio(int diretorioId) async {
    final response = await NetworkCaller().getRequest("${ApiLinks.allArquivos}/$diretorioId");
    if (response.isSuccess && response.body != null) {
      final data = response.body!['data']['dados'] ?? [];
      return List<Map<String, dynamic>>.from(data);
    }
    return [];
  }

  Future<bool> uploadArquivo({
    required Uint8List bytes,
    required String fileName,
    required int diretorioId,
    required int empresaId,
  }) async {
    var request = http.MultipartRequest('POST', Uri.parse(ApiLinks.uploadArquivo));
    request.fields['diretorioId'] = diretorioId.toString();
    request.fields['empresaId'] = empresaId.toString();
    request.files.add(http.MultipartFile.fromBytes('file', bytes, filename: fileName));

    var response = await request.send();
    return response.statusCode == 200;
  }

  Future<bool> deleteArquivo(int id) async {
    final response = await NetworkCaller().deleteRequest("${ApiLinks.deleteArquivo}/$id");
    return response.isSuccess;
  }

  Future<bool> marcarComoLido(int id) async {
    final response = await NetworkCaller().putRequest("${ApiLinks.updateArquivoLido}/$id");
    return response.isSuccess;
  }
}
